// Extraer datos del body
const body = $input.first().json.body || $input.first().json;

const companySlug = body.company_slug || 'default';
const filename = body.filename || 'document.pdf';
const category = body.category || 'general';
const fileBase64 = body.file || '';

// Limpiar el base64
let cleanBase64 = fileBase64;
if (cleanBase64.includes(',')) {
  cleanBase64 = cleanBase64.split(',')[1];
}

// Crear nombre de colección
const collectionName = 'company_' + companySlug.replace(/[^a-z0-9_-]/gi, '_').toLowerCase() + '_knowledge';

// Decodificar base64 a texto
// Para PDFs, extraemos el texto visible entre los streams
let extractedText = '';

try {
  const binaryString = atob(cleanBase64);

  // Intentar extraer texto de PDF
  if (filename.toLowerCase().endsWith('.pdf')) {
    // Buscar texto entre paréntesis en el PDF (método simple)
    const textMatches = binaryString.match(/\(([^)]+)\)/g) || [];
    const textParts = textMatches.map(m => m.slice(1, -1)).filter(t => t.length > 2 && /[a-zA-Z]/.test(t));

    // También buscar texto en streams decodificados
    const streamMatches = binaryString.match(/BT[\s\S]*?ET/g) || [];
    for (const stream of streamMatches) {
      const tjMatches = stream.match(/\[([^\]]+)\]\s*TJ/g) || [];
      for (const tj of tjMatches) {
        const parts = tj.match(/\(([^)]+)\)/g) || [];
        textParts.push(...parts.map(p => p.slice(1, -1)));
      }
    }

    extractedText = textParts.join(' ').replace(/\s+/g, ' ').trim();

    // Si no encontramos texto, puede ser un PDF escaneado
    if (extractedText.length < 50) {
      // Intentar obtener cualquier texto ASCII legible
      extractedText = binaryString.replace(/[^\x20-\x7E\n]/g, ' ').replace(/\s+/g, ' ').trim();
      // Filtrar solo partes que parezcan texto real
      const words = extractedText.split(' ').filter(w => w.length > 3 && /^[a-zA-Z]+$/.test(w));
      extractedText = words.join(' ');
    }
  } else {
    // Para archivos de texto plano
    extractedText = binaryString;
  }
} catch (e) {
  // Si falla la decodificación, intentar como UTF-8
  try {
    const bytes = Uint8Array.from(atob(cleanBase64), c => c.charCodeAt(0));
    extractedText = new TextDecoder('utf-8').decode(bytes);
  } catch (e2) {
    extractedText = '';
  }
}

// Limpiar el texto extraído
extractedText = extractedText
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '')
  .replace(/\s+/g, ' ')
  .trim();

if (!extractedText || extractedText.length < 20) {
  throw new Error('No se pudo extraer texto del documento. El PDF puede ser una imagen escaneada o estar protegido. Texto encontrado: ' + extractedText.substring(0, 100));
}

return {
  json: {
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName,
    text: extractedText,
    text_length: extractedText.length
  }
};

const text = $input.first().json.text || '';
const companySlug = $input.first().json.company_slug;
const filename = $input.first().json.filename;
const category = $input.first().json.category;
const collectionName = $input.first().json.collection_name;

const maxCharsPerChunk = 20000;
const chunks = [];

if (text.length <= maxCharsPerChunk) {
  chunks.push(text);
} else {
  for (let i = 0; i < text.length; i += maxCharsPerChunk - 500) {
    chunks.push(text.substring(i, i + maxCharsPerChunk));
  }
}

return chunks.map((chunk, index) => ({
  json: {
    text: chunk,
    chunk_index: index,
    total_chunks: chunks.length,
    company_slug: companySlug,
    filename: filename,
    category: category,
    collection_name: collectionName
  }
}));

const item = $input.first();
const embedding = item.json.data[0].embedding;
const prevData = $('Split into Chunks').item.json;

return {
  json: {
    id: `${prevData.filename}-${prevData.chunk_index}-${Date.now()}`,
    vector: embedding,
    payload: {
      text: prevData.text,
      filename: prevData.filename,
      category: prevData.category,
      company_slug: prevData.company_slug,
      chunk_index: prevData.chunk_index
    },
    collection_name: prevData.collection_name
  }
};

